import { describe, it, expect } from "vitest";
import { processScenario } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  describe("quote - base premiums", () => {
    it("empty item list yields premium of 5 G (processing fee only)", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [] }],
      });
      expect(result.results[0]).toEqual({ premium: 5 });
    });
    it("single sword for newcomer yields premium of 115 G", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "sword", cursed: false, enchantment: 3 }] }],
      });
      expect(result.results[0]).toEqual({ premium: 115 });
    });
    it("single amulet for newcomer yields premium of 71 G", () => {
      const result = processScenario({
        customer: { yearsWithMHPCO: 0 },
        steps: [{ op: "quote", items: [{ type: "amulet", cursed: false, enchantment: 2 }] }],
      });
      expect(result.results[0]).toEqual({ premium: 71 });
    });
    it.todo("single staff for newcomer yields premium of 93 G");
    it.todo("single potion for newcomer yields premium of 49 G");
    it.todo("sword and amulet for newcomer yields combined premium");
  });

  describe("quote - component pricing", () => {
    it.todo("two runes yield base premium of 50 G (2 × 25 G)");
    it.todo("three alike runes yield base premium of 60 G (block of 3)");
    it.todo("four runes yield base premium of 100 G (no block — not exactly 3)");
    it.todo("three runes and three moonstones yield two separate blocks (120 G base)");
    it.todo("two runes and one moonstone yield no block (75 G base, different types)");
  });

  describe("quote - item-level surcharges", () => {
    it.todo("cursed sword adds 50 % surcharge on sword base premium");
    it.todo("sword with enchantment 5 adds 30 % high-enchantment surcharge");
    it.todo("sword with enchantment 4 has no high-enchantment surcharge");
    it.todo("cursed sword with enchantment 5 applies both surcharges");
    it.todo("cursed surcharge on multi-item policy applies only to cursed item base premium");
  });

  describe("quote - policy-level modifiers", () => {
    it.todo("customer with exactly 2 years receives 20 % loyalty discount");
    it.todo("customer with fewer than 2 years receives no loyalty discount");
    it.todo("second quote receives 15 % follow-up discount");
    it.todo("first insurance surcharge of 10 % always applies regardless of customer history");
    it.todo("long-standing customer second contract stacks loyalty and follow-up discounts");
  });

  describe("quote - rounding", () => {
    it.todo("final premium rounds up in MHPCO's favor");
  });

  describe("claim - standard reimbursement", () => {
    it.todo("plain sword damage reimburses full amount minus 100 G deductible");
    it.todo("rune damage reimburses full amount minus 100 G deductible");
    it.todo("deductible applies once per damaged item in an incident");
  });

  describe("claim - special reimbursement clauses", () => {
    it.todo("damage to item with enchantment >= 8 is reimbursed at 50 % before deductible");
    it.todo("damage to dragon-material item is fully reimbursed (minus deductible)");
    it.todo("dragon material with enchantment >= 8 uses 50 % rule (not full reimbursement)");
    it.todo("dragon-material sword with enchantment 5 uses only dragon-material clause");
    it.todo("steel sword with enchantment 9 uses only the 50 % clause");
  });

  describe("claim - cap exhaustion", () => {
    it.todo("payout cap equals twice the total insurance sum");
    it.todo("payout is capped when claim exceeds remaining cap");
    it.todo("remaining cap decreases across successive claims on same policy");
    it.todo("cap is based on unmodified insurance values, not premium modifiers");
  });
});

