type Item = { type: string };
type Scenario = { steps: { op: string; items?: Item[] }[] };

const PROCESSING_FEE = 5;
const FIRST_INSURANCE_RATE = 0.10;
const COMPONENT_BASE = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PREMIUM = 60;

const quoteResult = (premium: number) => ({ results: [{ premium }] });

const blockAdjustment = (type: string, items: Item[]): number => {
  const count = items.filter((i) => i.type === type).length;
  return count === COMPONENT_BLOCK_SIZE
    ? COMPONENT_BLOCK_PREMIUM - count * COMPONENT_BASE
    : 0;
};

const COMPONENT_TYPES = ["rune", "moonstone"];

const ITEM_BASE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};
for (const type of COMPONENT_TYPES) ITEM_BASE[type] = COMPONENT_BASE;

export const processScenario = (scenario: Scenario): { results: { premium: number }[] } => {
  const items = scenario.steps[0].items ?? [];
  const policyBase = items.reduce((sum, item) => sum + ITEM_BASE[item.type], 0)
    + blockAdjustment("rune", items)
    + blockAdjustment("moonstone", items);
  const premium = Math.ceil(policyBase + policyBase * FIRST_INSURANCE_RATE + PROCESSING_FEE);
  return quoteResult(premium);
};

